import React, { useState } from "react";
import axios from "axios";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

function IndianStockDetails() {
  const [symbol, setSymbol] = useState("");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const handleFetch = async () => {
    setError("");
    setData(null);

    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data.");
    }
  };

  const renderChart = () => {
    if (!data || !data.price) return null;

    // Simulate chart data - Yahoo does NOT return historical series in your backend,
    // so for now we’ll duplicate the same price across fake dates to show a chart.
    const dummyDates = ["Day-4", "Day-3", "Day-2", "Day-1", "Today"];
    const dummyPrices = new Array(dummyDates.length).fill(data.price);

    return (
      <Line
        data={{
          labels: dummyDates,
          datasets: [
            {
              label: `${data.symbol} Price`,
              data: dummyPrices,
              borderColor: "blue",
              fill: false,
            },
          ],
        }}
        height={100}
      />
    );
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Indian Stock Details (Yahoo Finance)</h2>
      <input
        type="text"
        placeholder="Enter symbol (e.g. TCS)"
        value={symbol}
        onChange={(e) => setSymbol(e.target.value)}
      />
      <button onClick={handleFetch}>Fetch</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <div style={{ marginTop: "20px" }}>
          <h3>{data.name} ({data.symbol})</h3>

          <h4>Current Price</h4>
          <p>
            ₹{data.price} 
            &nbsp; | Change: {data.change} ({data.percentChange}%)
          </p>

          <h4>Fundamentals</h4>
          <ul>
            <li>Market Cap: {data.marketCap}</li>
            <li>PE Ratio: {data.peRatio}</li>
            <li>Dividend Yield: {data.dividendYield}</li>
            <li>52 Week High: {data.fiftyTwoWeekHigh}</li>
            <li>52 Week Low: {data.fiftyTwoWeekLow}</li>
          </ul>

          {renderChart()}
        </div>
      )}
    </div>
  );
}

export default IndianStockDetails;
